int PiLian_Write_Prat_Attr::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
    try
    {
        if(block == enum0)
        {
        //---------Enter your code here-----------
        }
        else if(block == string0)
        {
        //---------Enter your code here-----------
        }
        else if(block == string01)
        {
            SetStringBlockValue(string01, Utf8Text(CurrentWorkPart()->Name()));
        }
        else if(block == string02)
        {
        //---------Enter your code here-----------
        }
        else if(block == enum01)
        {
        //---------Enter your code here-----------
        }
        else if(block == enum02)
        {
        }
        else if(block == string03)
        {
        //---------Enter your code here-----------
        }
        else if(block == toggleManualQuantity)
        {
            RefreshQuantityInput(toggleManualQuantity, toggleAssemblyQuantity, string03, CurrentWorkPart());
        }
        else if(block == toggleLayerFilter)
        {
            RefreshLayerFilterInput(toggleLayerFilter, stringLayerStart, stringLayerEnd);
        }
        else if(block == stringLayerStart)
        {
        }
        else if(block == stringLayerEnd)
        {
        }
        else if(block == toggleAssemblyQuantity)
        {
            RefreshQuantityInput(toggleManualQuantity, toggleAssemblyQuantity, string03, CurrentWorkPart());
        }
        else if(block == openConfigButton)
        {
            OpenConfigFile();
        }
    }
    catch(exception& ex)
    {
        //---- Enter your exception handling code here -----
        PiLian_Write_Prat_Attr::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return 0;
}

//------------------------------------------------------------------------------
